import{c as h,S as i,j as a,m as o}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Học viên - Khóa học","description":"","frontmatter":{},"headers":[],"relativePath":"admin/hoc-vien-khoa-hoc.md","filePath":"admin/hoc-vien-khoa-hoc.md","lastUpdated":0}'),t={name:"admin/hoc-vien-khoa-hoc.md"};function l(c,n,g,r,e,s){return i(),a("div",null,[...n[0]||(n[0]=[o('<h1 id="hoc-vien-khoa-hoc" tabindex="-1">Học viên - Khóa học <a class="header-anchor" href="#hoc-vien-khoa-hoc" aria-label="Permalink to “Học viên - Khóa học”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/business/courseStudent</code></p><p>Đây là <strong>bảng quan hệ</strong> giữa học viên và khóa học mà họ đang sở hữu, giúp bạn:</p><ul><li>Tra cứu nhanh: học viên nào đang học khóa nào.</li><li>Gán khóa miễn phí cho học viên (VIP, khuyến mại).</li><li>Gia hạn thời hạn sử dụng khóa.</li><li>Thu hồi quyền học khi cần (vd: hoàn tiền).</li></ul><h2 id="danh-sach" tabindex="-1">Danh sách <a class="header-anchor" href="#danh-sach" aria-label="Permalink to “Danh sách”">​</a></h2><p>Cột chính:</p><ul><li>Tên học viên, Số điện thoại</li><li>Tên khóa học</li><li>Ngày bắt đầu, Ngày hết hạn</li><li><strong>Nguồn</strong>: Mua thường / Khuyến mãi / Gán thủ công / Đại lý</li><li>Mã hóa đơn liên quan (nếu mua)</li><li>Trạng thái (Đang hoạt động / Hết hạn / Bị thu hồi)</li></ul><h2 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h2><ul><li>Theo khóa học</li><li>Theo trạng thái</li><li>Theo nguồn</li><li>Theo khoảng ngày bắt đầu / hết hạn</li><li>Theo học viên (tìm theo tên/SĐT)</li></ul><h2 id="gan-khoa-cho-hoc-vien-thu-cong" tabindex="-1">Gán khóa cho học viên (thủ công) <a class="header-anchor" href="#gan-khoa-cho-hoc-vien-thu-cong" aria-label="Permalink to “Gán khóa cho học viên (thủ công)”">​</a></h2><ol><li>Bấm <strong>Gán khóa</strong>.</li><li>Chọn <strong>Học viên</strong> (gõ tên/SĐT để tìm).</li><li>Chọn <strong>Khóa học</strong>.</li><li>Cấu hình: <ul><li><strong>Thời hạn</strong> (số ngày, hoặc ngày kết thúc cố định)</li><li><strong>Nguồn</strong>: chọn <code>Gán thủ công</code> hoặc <code>Khuyến mãi</code></li><li><strong>Ghi chú</strong> (vd: &quot;Học viên VIP, miễn phí học kỳ 1&quot;)</li></ul></li><li>Bấm <strong>Lưu</strong>. Học viên có thể vào học ngay.</li></ol><h2 id="gan-hang-loat" tabindex="-1">Gán hàng loạt <a class="header-anchor" href="#gan-hang-loat" aria-label="Permalink to “Gán hàng loạt”">​</a></h2><p>Nếu cần gán cho nhiều học viên cùng lúc (vd cả một lớp offline):</p><ol><li>Bấm <strong>Gán hàng loạt</strong>.</li><li>Tải template Excel.</li><li>Điền: SĐT học viên, Mã khóa, Ngày bắt đầu, Số ngày sử dụng.</li><li>Upload lại → hệ thống xác nhận và gán đồng loạt.</li></ol><h2 id="gia-han" tabindex="-1">Gia hạn <a class="header-anchor" href="#gia-han" aria-label="Permalink to “Gia hạn”">​</a></h2><ul><li>Bấm icon <strong>Gia hạn</strong> trên dòng.</li><li>Nhập <strong>số ngày cần thêm</strong> (vd 30 ngày) hoặc <strong>ngày hết hạn mới</strong>.</li><li>Lưu.</li></ul><h2 id="thu-hoi-quyen-hoc-huy" tabindex="-1">Thu hồi quyền học (hủy) <a class="header-anchor" href="#thu-hoi-quyen-hoc-huy" aria-label="Permalink to “Thu hồi quyền học (hủy)”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Khi thu hồi, học viên ngay lập tức không vào được khóa. Hãy chắc chắn đã hoàn tiền hoặc đã thông báo cho học viên.</p></div><ol><li>Bấm icon <strong>Hủy</strong>.</li><li>Chọn lý do (Hoàn tiền / Vi phạm / Khác).</li><li>Xác nhận.</li></ol><h2 id="đoi-soat-voi-hoa-đon" tabindex="-1">Đối soát với Hóa đơn <a class="header-anchor" href="#đoi-soat-voi-hoa-đon" aria-label="Permalink to “Đối soát với Hóa đơn”">​</a></h2><ul><li>Mỗi dòng &quot;mua khóa&quot; tương ứng 1 chi tiết hóa đơn.</li><li>Bấm vào <strong>Mã hóa đơn</strong> để mở <a href="./hoa-don">Chi tiết hóa đơn</a> liên quan.</li><li>Khi có khiếu nại &quot;tôi đã thanh toán nhưng chưa vào được khóa&quot; → tra ở đây trước.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên báo &quot;không thấy khóa đã mua trong danh sách của mình&quot;.</strong> → Kiểm tra ở đây. Nếu <strong>không có dòng nào</strong> thì có thể giao dịch chưa hoàn tất (xem <a href="./hoa-don">Hóa đơn</a>). Nếu có dòng nhưng trạng thái Hết hạn → gia hạn lại.</p><p><strong>Có thể thấy danh sách học viên của 1 khóa cụ thể không?</strong> → Có. Vào <a href="./khoa-hoc">Khóa học</a> → mở chi tiết khóa → tab <strong>Học viên</strong>.</p><p><strong>Học viên mua 1 khóa 2 lần (có 2 dòng) - xử lý sao?</strong> → Có thể là cộng dồn thời hạn. Kiểm tra hóa đơn từng lần. Nếu là lỗi → hoàn tiền 1 lần và hủy 1 dòng tương ứng.</p>',25)])])}const m=h(t,[["render",l]]);export{d as __pageData,m as default};
